INSERT INTO master_sections (user_id, payload) VALUES
(null, '{"title":"Identidad AMTME","content":"A Mí Tampoco Me Explicaron es un podcast de acompañamiento emocional para hombres hispanos de 28 a 44 años. No es autoayuda, no es terapia, no es coaching. Es un refugio simbólico donde alguien habla desde adentro, no desde arriba. La voz es la de un par que también está aprendiendo.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Fuente de toda decisión editorial y de marca.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Misión y propósito","content":"Acompañar a hombres hispanos en el proceso de entender su mundo emocional — el vínculo, el apego, la identidad, la familia — sin moralizarlos ni diagnosticarlos. Crear el espacio que nadie les dio. La misión no es enseñar sino recordar. No vengo a explicar sino a caminar junto.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Marco para rechazar contenido que no cumpla este criterio.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Audiencia objetivo","content":"Hombres hispanos, 28-44 años. 81.5% audiencia mexicana. Perfil: hombres que no fueron enseñados a hablar de lo que sienten pero que lo sienten todo. Temas de mayor resonancia: relaciones románticas y rechazo (2x promedio de streams). Segundo grupo: identidad, trabajo, familia de origen.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Validado en datos Spotify for Creators mayo 2026.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Voz y tono editorial","content":"Voz: par, no gurú. Tono: íntimo, sobrio, honesto. Sin positivismo tóxico. Sin moralismo. Sin autorreferencia excesiva. Los 5 filtros editoriales: 1) ¿Acompaña o juzga? 2) ¿Habla desde adentro o desde arriba? 3) ¿Usa cliché o imagen real? 4) ¿Invita a recordar o a seguir instrucciones? 5) ¿El oyente se siente menos solo al terminar?","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Aplicar a cada guion antes de publicar.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Estructura narrativa AZTIYARTE","content":"A = Apertura del umbral (0:00-1:30): la herida o la pregunta que abre el episodio.\nZ = Zona de origen (1:30-3:00): de dónde viene esa herida, sin psicologizar.\nT = Tension point (3:00-5:00): el momento en que la herida se volvió patrón.\nI = Interior reveal (5:00-7:00): lo que realmente está pasando debajo.\nY = Yielding (7:00-9:00): el símbolo, la imagen, el giro.\nA = Acción simbólica (9:00-10:30): no consejo, sino movimiento.\nR = Reencuadre (10:30-11:30): la misma situación vista desde otro ángulo.\nT = Tierra firme (11:30-12:00): cierre que acompaña, no que resuelve.\nE = Eco (12:00-12:45): la pregunta que el oyente se lleva.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Duración objetivo: 12:45. Cada bloque es negociable excepto A y E.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Tarot como herramienta simbólica","content":"El tarot en AMTME es autoconocimiento, no predicción. Es un espejo, no un oráculo. Las lecturas de pago son encuentros de 30-45 minutos de introspección guiada. Precio actual: por DM directo. Precio objetivo membership: $9/mes con 1 lectura mensual incluida. El tarot nunca reemplaza terapia profesional — esto se dice explícitamente en cada lectura.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Membership landing page pendiente de deployment.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Sistema visual SB-01","content":"Paleta canónica activa:\n- Navy: #0C1F36 (fondo principal, texto sobre crema)\n- Lemon Lime / Yellowball: #FEE94B o #E8FF40 (acento principal, CTAs)\n- Crema: #F5F2EA (fondos secundarios, tarjetas)\n- Azul Grisáceo: #90A4B8 (texto secundario, bordes suaves)\n- Rojo AMTME: #E0211E (alertas, acciones destructivas)\n- Blanco: #FFFFFF (texto sobre navy)\n\nTipografía: Josefin Sans Bold (titulares), Special Elite Regular (cuerpo).\nReglas: sin cursivas, sin Barra de Navidad, estética suiza/ejecutiva.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Paleta anterior (Cobalt #1A1AE6) descartada. Esta es la única autorizada.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Métricas clave AMTME OS","content":"KPIs primarios:\n- Streams mensuales Spotify (baseline: verificar)\n- Tasa episodio→DM (objetivo: >0.5%)\n- DM→venta tarot (objetivo: >30%)\n- Ingresos mensuales (objetivo fase 1: $1,500-2,500 USD)\n\nKPIs secundarios:\n- Seguidores IG @amtmepodcast\n- Saves/shares por post\n- Retención promedio por episodio\n- Nuevos seguidores Spotify por episodio\n\nFrecuencia de revisión: mensual en tabla Métricas, semanal en ritual dominical.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Conectar Spotify for Creators API cuando esté disponible.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Modelo de monetización activo","content":"Capa 1 — Inmediata (activa): Lecturas de tarot por DM. Precio: variable. Conversión: por cultivar.\nCapa 2 — 30 días: Membership tarot $9/mes. Landing page diseñada, deployment pendiente.\nCapa 3 — 90 días: Producto digital (guía, mini-curso). Tema por definir desde episodios de mayor retención.\nCapa 4 — Long-term: Spotify for Creators income, afiliados, patrocinios alineados.\n\nIngreso objetivo fase 1: $1,500-2,500 USD/mes.\nIngreso objetivo fase 2: $5,000+ USD/mes.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Prioridad: deployment membership en los próximos 7 días.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Stack tecnológico AMTME","content":"Producción de audio: ElevenLabs (Voice ID: cOnR55b0OoT3XWd4hIUf, modelo eleven_multilingual_v2, Stability 0.65, Similarity 0.80).\nEdición video: CapCut.\nImágenes: Midjourney v6.1 (--cref para consistencia de rostro).\nDistribución: Spotify, Apple Podcasts, Instagram @amtmepodcast.\nApp operativa: AMTMEapp (Next.js + Supabase + Vercel).\nIA: Groq (principal), Gemini, Claude, Grok.\nEmail (pendiente): Brevo o Resend.\nPagos (pendiente): Stripe.","status":"vigente","priority":"media","version":1,"responsible":"Christian Villamar","notes":"ElevenLabs parámetros validados en EP.29.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Producción semanal SOPs","content":"Lunes: Definir tema + herida + símbolo del episodio.\nMartes: Investigación simbólica y narrativa.\nMiércoles: Escritura del guion (estructura AZTIYARTE).\nJueves: Grabación + primera edición.\nViernes: Edición final + assets visuales (12 piezas pipeline).\nSábado: Programación y preparación distribución.\nDomingo: Ritual de revisión — métricas semana anterior + plan próxima semana.\n\nDuración objetivo por episodio: 12:45 min.\nCiclo: 1 episodio/semana como mínimo sostenible.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Ritual dominical es irremplazable para la salud del OS.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Distribución y canales activos","content":"Primario: Spotify (host principal).\nSecundario: Apple Podcasts, otros agregadores vía distribuidor.\nRedes sociales: Instagram @amtmepodcast (principal), TikTok (secundario).\nPersonal: @yosoyvillamar (cross-promotion).\n\nFormatos de contenido IG: reels (clips episodio), carruseles (conceptos), stories (CTA diario), posts (citas + visual SB-01).\n16 blueprints visuales por episodio (BP-01 a BP-16).","status":"vigente","priority":"media","version":1,"responsible":"Christian Villamar","notes":"ManyChat integración pendiente para automatizar DM flows.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Episodios publicados — histórico","content":"EP.01-EP.28: Publicados en Spotify. Ver /episodios para detalle completo.\nEP.29: Familia, Dinero y Límites (guest: Rubén López @reycolopez97). Referencia histórica completa.\nEP.28: Dinámicas ansioso-evitativas.\nEP.34: ¿A quién estabas intentando salvar? (pipeline visual completo 12 piezas ejecutado).\nEP.35: En producción — enfoque en mecanismos de engagement psicológico.\n\nTotal: 34+ episodios al 01/06/2026.","status":"vigente","priority":"media","version":1,"responsible":"Christian Villamar","notes":"Actualizar mensualmente.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Bio oficial — Christian Villamar","content":"Christian Villamar (@yosoyvillamar) es el creador y host de A Mí Tampoco Me Explicaron. No viene como experto ni como coach — viene como alguien que también está aprendiendo a nombrarlo todo. Su trabajo es crear refugios simbólicos donde los hombres hispanos encuentren el lenguaje que nadie les enseñó para lo que sienten.\n\nFormación: comunicación, narrativa simbólica, tarot como herramienta de introspección.\nUbicación: Playa del Carmen, México.\nIdioma de trabajo: español neutro latinoamericano.","status":"vigente","priority":"media","version":1,"responsible":"Christian Villamar","notes":"Usar en pitches, presentaciones, notas de prensa.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Criterios de calidad editorial","content":"Un episodio está listo para publicar cuando:\n1. El oyente puede identificar la herida central en los primeros 90 segundos.\n2. No hay consejo directo — solo acompañamiento y símbolo.\n3. La estructura AZTIYARTE está completa (9 bloques).\n4. El CTA es uno solo, claro, no imperativo.\n5. La descripción Spotify tiene entre 150-200 palabras.\n6. Los assets visuales siguen paleta SB-01 sin excepción.\n7. La voz no suena a self-help, coaching ni psicología clínica.\n\nUn episodio NO debe publicarse si:\n- Contiene consejos directos tipo \"debes hacer X\".\n- Usa clichés motivacionales.\n- La herida no está identificada claramente.\n- El tono es condescendiente o didáctico.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Aplicar checklist pre-publicación en cada episodio.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Errores a evitar — editorial","content":"1. Sonar como podcast de autoayuda genérico.\n2. Usar palabras: sanar, crecer, evolucionar, vibrar, manifestar.\n3. Hablar desde la superioridad o la experiencia resuelta.\n4. Dar consejos directos disfrazados de reflexión.\n5. Episodios de más de 15 minutos sin justificación narrativa.\n6. Assets visuales que mezclen paletas antiguas (Cobalt) con SB-01.\n7. Publicar sin checklist completado.\n8. Acumular sin ejecutar — el enemigo número uno del OS.\n9. Perfeccionismo que paraliza el ciclo semanal.\n10. Validación externa antes de actuar.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Revisitar en ritual dominical mensualmente.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Automatización y agentes IA","content":"Agentes activos en AMTMEapp:\n- Revisión de Episodios: analiza campos faltantes y completa con Groq.\n- Generador de contenido: crea 8 formatos por episodio.\n- Seguimiento de leads: genera DM de follow-up por monetización lead.\n- Reportes de métricas: análisis automático mensual.\n\nPendiente de activar:\n- ManyChat: Instagram DM flows.\n- Zapier: Spotify metrics sync, email sequences.\n- Brevo/Resend: email nurture.\n- Stripe: pagos membership tarot.\n\nRegla de automatización: si se hace más de 3 veces manual, se automatiza.","status":"pendiente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Prioridad de deployment: membership landing > email capture > ManyChat.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Fases completadas del proyecto","content":"FASE 0: Identidad y marca (completada 2024).\nFASE 1: Producción regular semanal (completada 2024-2025, 28+ episodios).\nFASE 2: Sistema visual SB-01 (completada abril 2026).\nFASE 3: AMTMEapp v1 — sistema operativo digital (completada mayo-junio 2026).\n  - Landing pública\n  - Login + Supabase\n  - Dashboard operativo\n  - 12 páginas studio\n  - 3 providers IA\n  - Deployment Vercel\n\nFASE 4 (en curso): Monetización activada — membership, email funnel, Stripe.\nFASE 5 (planeada): Comunidad de pago, producto digital, patrocinios.","status":"vigente","priority":"media","version":1,"responsible":"Christian Villamar","notes":"Actualizar al completar cada fase.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Gestión de energía y burnout","content":"AMTME OS reconoce que el creador es el único recurso no reemplazable del sistema.\n\nSeñales de alerta burnout: perfeccionismo que paraliza, acumulación sin publicación, validación externa antes de actuar, ciclos semanales rotos por más de 2 semanas.\n\nProtocolo de recuperación:\n1. Reducir a 1 acción por día hasta recuperar ritmo.\n2. Ritual dominical como ancla — nunca saltarlo.\n3. Separar producción de estrategia — no mezclar en el mismo bloque de trabajo.\n4. Publicar aunque no sea perfecto — el estándar mínimo es suficiente.\n\nRegla de energía: si no hay energía para un episodio completo, publicar un clip de episodio anterior.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"La salud del creador es condición del OS, no variable opcional.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Guía de contenido IG — pilares","content":"Pilar 1: Emocional (40%) — clips de episodio, citas, reflexiones. Máxima retención.\nPilar 2: Educativo-simbólico (30%) — carruseles sobre conceptos (apego, herida, símbolo).\nPilar 3: Detrás del proceso (20%) — proceso de producción, herramientas, trabajo diario.\nPilar 4: Comercial (10%) — tarot, membership, productos. Nunca agresivo.\n\nFrecuencia mínima: 5 posts/semana.\nFormato prioritario: reels (mayor alcance).\nHorario óptimo: 7-9pm hora México.\nCTA por post: uno solo, claro, no imperativo.","status":"vigente","priority":"media","version":1,"responsible":"Christian Villamar","notes":"Ajustar porcentajes según datos de engagement mensual.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Roadmap próximos 90 días","content":"SEMANA 1-2 (junio 2026):\n- Deployment membership landing page tarot ($9/mes).\n- Activar email capture en landing pública.\n- Completar EP.35 con pipeline visual completo.\n\nMES 1 (junio 2026):\n- 4 episodios publicados.\n- Primer ingreso membership tarot.\n- AMTMEapp completamente funcional con datos reales.\n\nMES 2 (julio 2026):\n- Lanzar primer producto digital.\n- Email list: objetivo 200 suscriptores.\n- Ingresos objetivo: $500-800 USD.\n\nMES 3 (agosto 2026):\n- Ingresos objetivo: $1,500 USD.\n- ManyChat Instagram DM flows activos.\n- Spotify: objetivo 10K streams mensuales.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Revisar y ajustar en ritual dominical de cada semana.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Política operativa — reglas no negociables","content":"1. Un episodio por semana mínimo. Sin excepción por 6+ semanas consecutivas.\n2. Checklist pre-publicación completado antes de publicar.\n3. Ritual dominical: 30-60 min de revisión y planificación.\n4. Paleta SB-01 en TODOS los assets visuales, sin excepciones.\n5. Sin consejo directo en ningún episodio.\n6. Sin clichés de autoayuda en ninguna pieza de contenido.\n7. El CTA de cada episodio es uno solo.\n8. Toda decisión estratégica pasa por el filtro de los 5 criterios editoriales.\n9. Monetización se menciona en contenido con proporción 1:10 (1 comercial por 10 de valor).\n10. Los datos de métricas se registran antes del día 5 de cada mes.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Estas reglas son el núcleo del AMTME OS. No se negocian.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Definición de éxito AMTME","content":"Éxito a 6 meses: $1,500-2,500 USD/mes de ingresos recurrentes + 10K streams mensuales Spotify + comunidad que retroalimenta la producción.\n\nÉxito a 12 meses: $5,000+ USD/mes + libro o producto digital en mercado + AMTME reconocido como referencia en su nicho dentro de México y LATAM.\n\nÉxito no es: tener el podcast más escuchado de habla hispana. Es ser el podcast más necesario para el hombre que lo escucha. 1 oyente que dice 'esto cambió algo' vale más que 10,000 que lo ponen de fondo.\n\nEl proyecto existe para crear libertad financiera que permita seguir creando con integridad.","status":"vigente","priority":"alta","version":1,"responsible":"Christian Villamar","notes":"Leer en momentos de duda sobre dirección estratégica.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Gestión de relaciones y comunidad","content":"Audiencia activa: hombres que comentan, envían DMs sobre episodios específicos.\nPatrón de engagement: mayor actividad en episodios sobre rechazo y relaciones románticas.\n\nProtocolo DM:\n1. Responder en 24-48h.\n2. Si el DM menciona dolor real: responder con acompañamiento, no consejo.\n3. Si el DM es potencial lead tarot: responder con propuesta y precio claro.\n4. Nunca prometer disponibilidad ilimitada.\n\nGuests: criterio — alineación con la misión, no con el número de seguidores.\nEP.29 referencia: Rubén López @reycolopez97, episodio Familia, Dinero y Límites.","status":"vigente","priority":"media","version":1,"responsible":"Christian Villamar","notes":"ManyChat pendiente para automatizar primera respuesta en DMs.","last_reviewed_at":"2026-06-01"}'),
(null, '{"title":"Recursos de referencia y aprendizaje","content":"Libros clave: apego adulto, psicología simbólica, narrativa oral, comunicación emocional masculina.\n\nPodcasts de referencia (estudio, no competencia): podcasts de largo aliento emocional en inglés que han logrado monetización real.\n\nHerramientas de aprendizaje activo:\n- Spotify for Creators: datos de retención por segmento.\n- Instagram Insights: contenido de mayor saves/shares.\n- DMs directos: feedback cualitativo más valioso.\n\nRegla de aprendizaje: solo incorporar nueva información si modifica una decisión actual. Aprendizaje sin aplicación = acumulación sin ejecución.","status":"vigente","priority":"baja","version":1,"responsible":"Christian Villamar","notes":"Evitar consumo pasivo de contenido sobre podcasting y marketing.","last_reviewed_at":"2026-06-01"}');
